class Solution:

    def validPermutation(self, n, nums): return sum(v == i + 1 for i, v in enumerate(nums)) == n




def read_ints():
	return list(map(int, input().split()))




def main():
	try:
		t = read_ints()[0]
		arr = read_ints()
		print(Solution().validPermutation(t, arr))
	except Exception as e:
		pass



if __name__ == '__main__':
	main()

