class Solution {
public:
bool validPermutation(int n, vector<int>& nums) {
	int count = 0;
	for (int i = 0; i < n; i++) {
		if (nums[i] <= i + 1) count++;
	}
	return count == n;
}
};



#include <iostream>
#include <vector>

int main() {
	int n;
	std::cin >> n;
	int x;
	std::vector<int> nums;
	for (int i = 0; i < n; i++) {
		std::cin >> x;
		nums.push_back(x);
	}
	std::cout << (Solution().validPermutation(n, nums) ? "true" : "false") << '\n';
	return 0;
}
